import java.util.Scanner;

public class SecureBufferCopy {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        int len = Math.min(name.length(), 10); // Limit to the size of buffer
        char[] buffer = new char[len];

        // Safe copy to prevent buffer overflow
        for (int i = 0; i < len; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer copy successful. Data stored in buffer: " + new String(buffer));
    }
}

